wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(157830646018999284)
,p_plug_name=>'Ostatnie wyniki'
,p_title=>'Ostatnie wyniki'
,p_region_css_classes=>'&KOLOR_KLASA.'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>70
,p_plug_new_grid_row=>false
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    m.data,',
'    dg.nazwa_druzyny || '' '' || m.wynik_gospodarza || '':'' || m.wynik_goscia || '' '' || dgo.nazwa_druzyny as wynik_mecz,',
'    r.nazwa_rozgrywek as liga,',
'    CASE ',
'        WHEN (m.druzyna_gospodarz_id = 1 AND m.wynik_gospodarza > m.wynik_goscia) OR ',
'             (m.druzyna_gosc_id = 1 AND m.wynik_goscia > m.wynik_gospodarza) THEN ''Wygrana''',
'        WHEN m.wynik_gospodarza = m.wynik_goscia THEN ''Remis''',
'        ELSE ''Przegrana''',
'    END as status,',
'    CASE ',
'        WHEN (m.druzyna_gospodarz_id = 1 AND m.wynik_gospodarza > m.wynik_goscia) OR ',
'             (m.druzyna_gosc_id = 1 AND m.wynik_goscia > m.wynik_gospodarza) THEN ''is-success''',
'        WHEN m.wynik_gospodarza = m.wynik_goscia THEN ''u-warning''',
'        ELSE ''u-danger''',
'    END as kolor_klasa,',
'    -- Dodajemy ikony dla lepszego efektu',
'    CASE ',
'        WHEN (m.druzyna_gospodarz_id = 1 AND m.wynik_gospodarza > m.wynik_goscia) OR ',
'             (m.druzyna_gosc_id = 1 AND m.wynik_goscia > m.wynik_gospodarza) THEN ''fa-check-circle''',
'        WHEN m.wynik_gospodarza = m.wynik_goscia THEN ''fa-minus-circle''',
'        ELSE ''fa-times-circle''',
'    END as ikona',
'FROM mecz m',
'JOIN druzyna dg ON m.druzyna_gospodarz_id = dg.druzyna_id',
'JOIN druzyna dgo ON m.druzyna_gosc_id = dgo.druzyna_id',
'JOIN rozgrywki r ON m.rozgrywki_id = r.rozgrywki_id',
'WHERE m.data <= TO_DATE(''2026-01-24'', ''YYYY-MM-DD'')'))
,p_query_order_by_type=>'STATIC'
,p_query_order_by=>'DATA DESC'
,p_template_component_type=>'REPORT'
,p_lazy_loading=>false
,p_plug_source_type=>'TMPL_THEME_42$TIMELINE'
,p_plug_query_num_rows=>6
