wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(206431783509673070)
,p_plug_name=>'Statystyki'
,p_title=>'Statystyki'
,p_region_template_options=>'#DEFAULT#:t-Region--removeHeader js-removeLandmark:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>10
,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_wartosc_kadry   NUMBER;',
'  v_liczba_pilkarzy NUMBER;',
'  v_liczba_kontuzji NUMBER;',
'  v_mecze_sezon     NUMBER;',
'  v_wartosc_fmt     VARCHAR2(100);',
'BEGIN',
'  -- 1. Pobranie danych',
'  v_wartosc_kadry := OBLICZ_WARTOSC_KADRY(1);',
'  ',
'  SELECT COUNT(*) INTO v_liczba_pilkarzy FROM zawodnik WHERE druzyna_id = 1;',
'  ',
'  SELECT COUNT(*) INTO v_liczba_kontuzji FROM zawodnik ',
'  WHERE druzyna_id = 1 AND czy_kontuzjowny = ''T'';',
'',
unistr('  -- Liczba mecz\00F3w do 24 stycznia 2026'),
'  SELECT COUNT(*) INTO v_mecze_sezon FROM mecz ',
'  WHERE (druzyna_gospodarz_id = 1 OR druzyna_gosc_id = 1)',
'    AND data <= TO_DATE(''2026-01-24'', ''YYYY-MM-DD'');',
'',
unistr('  v_wartosc_fmt := TRIM(TO_CHAR(v_wartosc_kadry, ''999G999G999G999'')) || '' \20AC'';'),
'',
unistr('  -- 2. HTML (Ulepszona responsywno\015B\0107 i mniejsze czcionki)'),
'  htp.p(''<style>',
'    .stat-card {',
'        background: white; ',
'        padding: 30px 15px; ',
'        border-radius: 16px; ',
'        box-shadow: 0 10px 25px rgba(0,0,0,0.06); ',
'        flex: 1; ',
'        min-width: 200px; /* Zmniejszone min-width dla lepszego upakowania */',
'        text-align: center; ',
'        display: flex; ',
'        flex-direction: column; ',
'        justify-content: center;',
'        transition: transform 0.3s ease, box-shadow 0.3s ease;',
'    }',
'    .stat-card:hover {',
'        transform: translateY(-5px);',
'        box-shadow: 0 15px 35px rgba(0,0,0,0.1);',
'    }',
'    .stat-icon {',
'        font-size: 3.5rem; /* Zmniejszona ikona z 4.5rem */',
'        margin-bottom: 15px;',
'    }',
'    .stat-label {',
'        font-size: 0.9rem; /* Zmniejszony napis z 1.1rem */',
'        color: #888; ',
'        font-weight: bold; ',
'        text-transform: uppercase; ',
'        letter-spacing: 1px;',
'    }',
'    .stat-value {',
unistr('        font-size: 2.2rem; /* Zmniejszona g\0142\00F3wna liczba z 3.2rem */'),
'        font-weight: 900; ',
'        color: #333; ',
'        margin-top: 5px;',
unistr('        white-space: nowrap; /* Zapobiega \0142amaniu symbolu euro do nowej linii */'),
'    }',
'',
unistr('    /* Media Queries dla mniejszych ekran\00F3w - automatyczne zmniejszanie tekstu */'),
'    @media (max-width: 1400px) {',
'        .stat-value { font-size: 1.8rem; }',
'        .stat-icon { font-size: 3rem; }',
'    }',
'    @media (max-width: 768px) {',
'        .stat-value { font-size: 1.5rem; }',
'        .stat-card { padding: 20px 10px; }',
'    }',
'  </style>'');',
'',
'  htp.p(''<div style="display: flex; gap: 20px; justify-content: space-between; flex-wrap: wrap; margin-bottom: 40px; font-family: sans-serif; width: 100%;">'');',
'',
unistr('    -- KAFELEK 1: LICZBA ZAWODNIK\00D3W'),
'    htp.p(''<div class="stat-card" style="border-bottom: 8px solid #056ace;">'');',
'       htp.p(''<div class="stat-icon" style="color: #056ace;"><i class="fa fa-users"></i></div>'');',
'       htp.p(''<div class="stat-label">Zawodnicy</div>'');',
'       htp.p(''<div class="stat-value">'' || v_liczba_pilkarzy || ''</div>'');',
'    htp.p(''</div>'');',
'',
unistr('    -- KAFELEK 2: WARTO\015A\0106 KADRY (Kluczowa zmiana czcionki dla symbolu \20AC)'),
'    htp.p(''<div class="stat-card" style="border-bottom: 8px solid #28a745;">'');',
'       htp.p(''<div class="stat-icon" style="color: #28a745;"><i class="fa fa-money"></i></div>'');',
unistr('       htp.p(''<div class="stat-label">Warto\015B\0107 Kadry</div>'');'),
'       htp.p(''<div class="stat-value" style="color: #28a745;">'' || v_wartosc_fmt || ''</div>'');',
'    htp.p(''</div>'');',
'',
'    -- KAFELEK 3: MECZE W SEZONIE',
'    htp.p(''<div class="stat-card" style="border-bottom: 8px solid #6f42c1;">'');',
'       htp.p(''<div class="stat-icon" style="color: #6f42c1;"><i class="fa fa-calendar-check-o"></i></div>'');',
'       htp.p(''<div class="stat-label">Mecze w sezonie</div>'');',
'       htp.p(''<div class="stat-value">'' || v_mecze_sezon || ''</div>'');',
'    htp.p(''</div>'');',
'',
'    -- KAFELEK 4: KONTUZJE',
'    htp.p(''<div class="stat-card" style="border-bottom: 8px solid #dc3545;">'');',
'       htp.p(''<div class="stat-icon" style="color: #dc3545;"><i class="fa fa-medkit"></i></div>'');',
'       htp.p(''<div class="stat-label">Kontuzjowani</div>'');',
'       htp.p(''<div class="stat-value" style="color: #dc3545;">'' || v_liczba_kontuzji || ''</div>'');',
'    htp.p(''</div>'');',
'',
'  htp.p(''</div>'');',
'END;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(206431923346673071)
,p_plug_name=>unistr('Najbli\017Csze Mecze')
,p_title=>unistr('Najbli\017Csze Mecze')
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>60
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    m.data,',
'    m.godzina_meczu,',
'    dg.nazwa_druzyny || '' vs '' || dgo.nazwa_druzyny as mecz,',
'    o.nazwa_obiektu as stadion,',
'    r.nazwa_rozgrywek as liga,',
'    CASE WHEN dg.druzyna_id = 1 THEN ''U siebie'' ELSE ''Wyjazd'' END as lokalizacja',
'FROM mecz m',
'JOIN druzyna dg ON m.druzyna_gospodarz_id = dg.druzyna_id',
'JOIN druzyna dgo ON m.druzyna_gosc_id = dgo.druzyna_id',
'JOIN rozgrywki r ON m.rozgrywki_id = r.rozgrywki_id',
'JOIN obiekt o ON m.obiekt_id = o.obiekt_id',
'WHERE m.data >= TO_DATE(''2026-01-24'', ''YYYY-MM-DD'')',
'ORDER BY m.data ASC',
'FETCH FIRST 3 ROWS ONLY'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
);
