wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(171177983942574476)
,p_plug_name=>'players_list'
,p_title=>unistr('Lista Zawodnik\00F3w')
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>30
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    z.zawodnik_id,',
'    z.imie,',
'    z.nazwisko,',
'    z.data_urodzenia,',
'    TRUNC(MONTHS_BETWEEN(SYSDATE, z.data_urodzenia)/12) as wiek,',
'    z.narodowosc,',
'    z.pozycja,',
'    z.numer_koszulki,',
'    z.pensja,              ',
'    z.wartosc_rynkowa,',
'    z.status_zawodnika,',
'    z.czy_kontuzjowny,',
'    z.data_rozpoczecia_kontraktu,',
'    z.data_zakonczenia_kontraktu,',
'    CASE ',
'        WHEN z.data_zakonczenia_kontraktu < ADD_MONTHS(SYSDATE, 6) ',
unistr('        THEN ''UWAGA: Kontrakt wygasa wkr\00F3tce!'''),
'        ELSE NULL',
'    END as alert_kontrakt,',
'    z.druzyna_id,',
'    z.wzrost,',
'    z.waga,',
'    z.zdjecie_url',
'FROM ZAWODNIK z',
'LEFT JOIN DRUZYNA d ON z.druzyna_id = d.druzyna_id'))
