wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(204517621884215300)
,p_plug_name=>'Statystyki Klubu'
,p_title=>'Statystyki Klubu'
,p_plug_display_sequence=>10
,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_wartosc_kadry  NUMBER;',
'  v_liczba_pilkarzy NUMBER;',
'  v_liczba_kontuzji NUMBER;',
'  v_srednia_wieku   NUMBER;',
'  v_wartosc_fmt    VARCHAR2(100);',
'BEGIN',
unistr('  -- 1. U\017Cycie Twojej funkcji (zak\0142adamy ID klubu = 1, FC Barcelona)'),
'  v_wartosc_kadry := OBLICZ_WARTOSC_KADRY(1);',
'  ',
'  -- 2. Pobranie danych statystycznych',
'  SELECT ',
'    COUNT(*), ',
'    SUM(CASE WHEN czy_kontuzjowny = ''T'' THEN 1 ELSE 0 END),',
'    ROUND(AVG(MONTHS_BETWEEN(SYSDATE, data_urodzenia)/12), 1) -- Obliczenie wieku',
'  INTO ',
'    v_liczba_pilkarzy, ',
'    v_liczba_kontuzji,',
'    v_srednia_wieku',
'  FROM zawodnik',
'  WHERE druzyna_id = 1;',
'',
'  -- 3. Formatowanie',
unistr('  v_wartosc_fmt := TRIM(TO_CHAR(v_wartosc_kadry, ''999G999G999G999'')) || '' \20AC'';'),
'',
'  -- 4. HTML (Centrowane Kafelki)',
'  htp.p(''<div style="display: flex; gap: 20px; justify-content: center; flex-wrap: wrap; margin-bottom: 30px;">'');',
'  ',
unistr('    -- KAFELEK 1: WARTO\015A\0106 (Zielony)'),
'    htp.p(''<div style="background: white; padding: 20px; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); width: 260px; text-align: center; border-top: 4px solid #28a745;">'');',
unistr('       htp.p(''<div style="font-size: 0.85rem; color: #666; font-weight: bold; text-transform: uppercase; letter-spacing: 1px;">Warto\015B\0107 Kadry</div>'');'),
'       htp.p(''<div style="font-size: 1.8rem; font-weight: 800; color: #28a745; margin-top: 10px;">'' || v_wartosc_fmt || ''</div>'');',
'    htp.p(''</div>'');',
'',
unistr('    -- KAFELEK 2: LICZBA PI\0141KARZY (Niebieski)'),
'    htp.p(''<div style="background: white; padding: 20px; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); width: 200px; text-align: center; border-top: 4px solid #056ace;">'');',
'       htp.p(''<div style="font-size: 0.85rem; color: #666; font-weight: bold; text-transform: uppercase; letter-spacing: 1px;">Zawodnicy</div>'');',
'       htp.p(''<div style="font-size: 2.5rem; font-weight: 800; color: #333; line-height: 1; margin-top: 5px;">'' || v_liczba_pilkarzy || ''</div>'');',
'    htp.p(''</div>'');',
'',
'    -- KAFELEK 3: KONTUZJE (Czerwony)',
'    htp.p(''<div style="background: white; padding: 20px; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); width: 200px; text-align: center; border-top: 4px solid #dc3545;">'');',
'       htp.p(''<div style="font-size: 0.85rem; color: #666; font-weight: bold; text-transform: uppercase; letter-spacing: 1px;">Kontuzje</div>'');',
'       htp.p(''<div style="font-size: 2.5rem; font-weight: 800; color: #dc3545; line-height: 1; margin-top: 5px;">'' || v_liczba_kontuzji || ''</div>'');',
'    htp.p(''</div>'');',
'',
unistr('    -- KAFELEK 4: \015AREDNIA WIEKU (Szary/Info)'),
'    htp.p(''<div style="background: white; padding: 20px; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); width: 200px; text-align: center; border-top: 4px solid #17a2b8;">'');',
unistr('       htp.p(''<div style="font-size: 0.85rem; color: #666; font-weight: bold; text-transform: uppercase; letter-spacing: 1px;">\015Arednia Wieku</div>'');'),
'       htp.p(''<div style="font-size: 2.5rem; font-weight: 800; color: #333; line-height: 1; margin-top: 5px;">'' || v_srednia_wieku || ''<span style="font-size: 1rem; color:#999;"> lat</span></div>'');',
'    htp.p(''</div>'');',
'',
'  htp.p(''</div>'');',
'END;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(204517735476215301)
,p_plug_name=>'Liderzy Sezonu'
,p_title=>'Liderzy Sezonu'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc:t-CardsRegion--styleA'
,p_plug_template=>2072724515482255512
,p_plug_display_sequence=>20
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    z.zawodnik_id,',
'    z.imie || '' '' || z.nazwisko as PILKARZ,',
'    z.pozycja,',
'    NVL(s.liczba_bramek, 0) || '' Goli'' as METRYKA_1,',
'    NVL(s.liczba_asyst, 0) || '' Asyst'' as METRYKA_2,',
unistr('    ''\015Ar. ocena: '' || NVL(TO_CHAR(OBLICZ_SREDNIA_OCENE_ZAWODNIKA(z.zawodnik_id, ''2025/26'')), ''-'') as OCENA,'),
'    ''u-color-1'' as COLOR_CLASS ',
'FROM zawodnik z',
'JOIN statystyka s ON z.zawodnik_id = s.zawodnik_id',
'WHERE z.druzyna_id = 1 ',
'  AND s.sezon = ''2025/26''',
'ORDER BY (NVL(s.liczba_bramek, 0) + NVL(s.liczba_asyst, 0)) DESC',
'FETCH FIRST 3 ROWS ONLY'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows_type=>'SCROLL'
,p_show_total_row_count=>false
);
