wwv_flow_imp_page.create_page_validation(
 p_id=>wwv_flow_imp.id(204518075884215305)
,p_tabular_form_region_id=>wwv_flow_imp.id(171177983942574476)
,p_validation_name=>unistr('Blokuj usuwanie zawodnika z histori\0105')
,p_validation_sequence=>10
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'BEGIN',
unistr('    -- 1. NAJWA\017BNIEJSZE: Sprawd\017A, czy u\017Cytkownik w og\00F3le pr\00F3buje USUN\0104\0106 wiersz.'),
unistr('    -- Je\015Bli status to ''U'' (Update/Edycja) lub ''C'' (Create/Dodawanie), '),
unistr('    -- to przerywamy walidacj\0119 i zwracamy NULL (czyli brak b\0142\0119du).'),
'    IF :APEX$ROW_STATUS != ''D'' THEN',
'        RETURN NULL;',
'    END IF;',
'',
unistr('    -- 2. DALSZA LOGIKA (Wykonuje si\0119 tylko, gdy :APEX$ROW_STATUS = ''D'')'),
'    DECLARE',
'        v_count NUMBER := 0;',
'    BEGIN',
'        -- Sprawdzamy czy ma statystyki, mecze lub transfery',
'        SELECT count(*) INTO v_count FROM (',
'            SELECT 1 FROM statystyka WHERE zawodnik_id = :ZAWODNIK_ID',
'            UNION ALL',
'            SELECT 1 FROM statystyka_meczowa WHERE zawodnik_id = :ZAWODNIK_ID',
'            UNION ALL',
'            SELECT 1 FROM transfer WHERE zawodnik_id = :ZAWODNIK_ID',
'        );',
'',
'        IF v_count > 0 THEN',
unistr('            RETURN ''Nie mo\017Cna usun\0105\0107 zawodnika ('' || :IMIE || '' '' || :NAZWISKO || ''), poniewa\017C posiada histori\0119 w systemie. Zmie\0144 jego status na "Sprzedany" lub "Nieaktywny".'';'),
'        END IF;',
'    END;',
'',
unistr('    RETURN NULL; -- Wszystko ok, mo\017Cna usuwa\0107'),
'END;'))
,p_validation2=>'PLSQL'
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_always_execute=>'Y'
,p_associated_column=>'ZAWODNIK_ID'
,p_error_display_location=>'INLINE_WITH_FIELD_AND_NOTIFICATION'
);
