,p_plug_display_sequence=>30
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    z.zawodnik_id,',
'    z.imie,',
'    z.nazwisko,',
'    z.data_urodzenia,',
'    floor(months_between(sysdate, z.data_urodzenia)/12) as wiek, -- Wyliczenie wieku',
'    z.narodowosc,',
'    z.pozycja,',
'    z.numer_koszulki,',
unistr('    d.nazwa_druzyny, -- Pobranie nazwy z tabeli po\0142\0105czonej'),
'    z.wzrost,',
'    z.waga,',
'    z.pensja,',
'    z.wartosc_rynkowa,',
'    z.data_rozpoczecia_kontraktu,',
'    z.data_zakonczenia_kontraktu,',
'    z.status_zawodnika,',
'    z.czy_kontuzjowny,',
'    z.opis_kontuzji,',
'    z.zdjecie_url,',
'    z.data_odejscia,',
'    z.data_powrotu',
'FROM zawodnik z',
'LEFT JOIN druzyna d ON z.druzyna_id = d.druzyna_id',
'WHERE z.zawodnik_id = :P4_ZAWODNIK_ID'))
,p_is_editable=>false
,p_plug_source_type=>'NATIVE_FORM'
