'    d.druzyna_id,',
'    d.nazwa_druzyny,',
'    d.miasto,',
'    d.kraj,',
'    to_char(d.data_zalozenia, ''YYYY'') as rok_zalozenia,',
'    d.herb_url,',
'    o.nazwa_obiektu,',
'    o.pojemnosc,',
'    oblicz_wartosc_kadry(d.druzyna_id) as wartosc_kadry',
'FROM druzyna d',
'LEFT JOIN obiekt o ON d.obiekt_id = o.obiekt_id',
'WHERE d.druzyna_id = :P5_DRUZYNA_ID'))
,p_is_editable=>false
,p_plug_source_type=>'NATIVE_FORM'
);
