 p_id=>wwv_flow_imp.id(190366862634377691)
,p_name=>unistr('Historia Spotka\0144')
,p_title=>unistr('Historia Spotka\0144')
,p_template=>4072358936313175081
,p_display_sequence=>30
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    m.sezon,',
'    m.data,',
'    r.nazwa_rozgrywek,',
'    CASE WHEN m.druzyna_gospodarz_id = 1 THEN ''Dom'' ELSE ''Wyjazd'' END as gdzie,',
'    m.wynik_gospodarza || '' : '' || m.wynik_goscia as wynik,',
'    o.nazwa_obiektu',
'FROM mecz m',
'JOIN rozgrywki r ON m.rozgrywki_id = r.rozgrywki_id',
'JOIN obiekt o ON m.obiekt_id = o.obiekt_id',
'WHERE',
'    (m.druzyna_gospodarz_id = :P5_DRUZYNA_ID AND m.druzyna_gosc_id = 1)',
'    OR',
'    (m.druzyna_gosc_id = :P5_DRUZYNA_ID AND m.druzyna_gospodarz_id = 1)',
'ORDER BY m.data DESC'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2538654340625403440
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
