wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(190368296576377705)
,p_plug_name=>unistr('Nag\0142\00F3wek Meczu')
,p_title=>unistr('Nag\0142\00F3wek Meczu')
,p_region_name=>'score-region'
,p_region_template_options=>'#DEFAULT#:t-Region--removeHeader js-removeLandmark:t-Region--noBorder:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>20
,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_gospodarz      VARCHAR2(100);',
'  v_gospodarz_logo VARCHAR2(500);',
'  v_gosc           VARCHAR2(100);',
'  v_gosc_logo      VARCHAR2(500);',
'  v_wynik          VARCHAR2(50);',
'  v_data           VARCHAR2(50);',
'  v_stadion        VARCHAR2(200);',
'  v_rozgrywki      VARCHAR2(100);',
'BEGIN',
'  -- 1. POBRANIE DANYCH DO ZMIENNYCH',
'  SELECT ',
'    dg.nazwa_druzyny,',
'    NVL(dg.herb_url, ''https://cdn-icons-png.flaticon.com/512/18/18404.png''),',
'    dgo.nazwa_druzyny,',
'    NVL(dgo.herb_url, ''https://cdn-icons-png.flaticon.com/512/18/18404.png''),',
'    CASE WHEN m.wynik_gospodarza IS NOT NULL THEN m.wynik_gospodarza || '' : '' || m.wynik_goscia ELSE ''- : -'' END,',
'    to_char(m.data, ''DD.MM.YYYY'') || '' | '' || m.godzina_meczu,',
'    o.nazwa_obiektu,',
'    r.nazwa_rozgrywek',
'  INTO ',
'    v_gospodarz, v_gospodarz_logo, v_gosc, v_gosc_logo, v_wynik, v_data, v_stadion, v_rozgrywki',
'  FROM mecz m',
'  JOIN druzyna dg ON m.druzyna_gospodarz_id = dg.druzyna_id',
'  JOIN druzyna dgo ON m.druzyna_gosc_id = dgo.druzyna_id',
'  JOIN obiekt o ON m.obiekt_id = o.obiekt_id',
'  JOIN rozgrywki r ON m.rozgrywki_id = r.rozgrywki_id',
'  WHERE m.mecz_id = :P9_MECZ_ID;',
'',
'  -- 2. GENEROWANIE CZYSTEGO HTML (BEZ TABEL APEXA)',
'  htp.p(''<div style="width: 100%; display: flex; justify-content: center; margin-bottom: 20px;">'');',
'  ',
'    htp.p(''<div style="',
'        display: flex; ',
'        align-items: center; ',
'        justify-content: space-between; ',
'        width: 100%; ',
'        max-width: 900px; ',
'        padding: 20px; ',
'        background: #f9f9f9; ',
'        border-radius: 12px; ',
'        box-shadow: 0 4px 6px rgba(0,0,0,0.1);',
'    ">'');',
'',
'      -- LEWA (GOSPODARZ)',
'      htp.p(''<div style="flex: 1; text-align: center;">'');',
'        htp.p(''<img src="'' || v_gospodarz_logo || ''" style="height: 90px; width: auto; object-fit: contain; margin-bottom: 10px;">'');',
'        htp.p(''<h2 style="margin: 0; font-size: 1.4rem; color: #333;">'' || v_gospodarz || ''</h2>'');',
'      htp.p(''</div>'');',
'',
unistr('      -- \015ARODEK (WYNIK)'),
'      htp.p(''<div style="flex: 0 0 220px; text-align: center;">'');',
'        htp.p(''<div style="font-size: 3.5rem; font-weight: 800; color: #056ace; line-height: 1;">'' || v_wynik || ''</div>'');',
'        htp.p(''<div style="margin-top: 10px; color: #666; font-size: 0.9rem; font-weight: bold;">'' || v_data || ''</div>'');',
'        htp.p(''<div style="margin-top: 5px; color: #999; font-size: 0.8rem;">'' || v_rozgrywki || ''<br><span style="color: #777;">'' || v_stadion || ''</span></div>'');',
'      htp.p(''</div>'');',
'',
unistr('      -- PRAWA (GO\015A\0106)'),
'      htp.p(''<div style="flex: 1; text-align: center;">'');',
'        htp.p(''<img src="'' || v_gosc_logo || ''" style="height: 90px; width: auto; object-fit: contain; margin-bottom: 10px;">'');',
'        htp.p(''<h2 style="margin: 0; font-size: 1.4rem; color: #333;">'' || v_gosc || ''</h2>'');',
'      htp.p(''</div>'');',
'',
'    htp.p(''</div>''); -- koniec karty',
'  htp.p(''</div>''); -- koniec wrappera',
'',
'EXCEPTION',
'  WHEN NO_DATA_FOUND THEN',
'    htp.p(''<div style="text-align:center">Brak danych meczu.</div>'');',
'END;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
);
