wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(190369194952377714)
,p_name=>'Raport meczowy'
,p_title=>'Raport meczowy'
,p_parent_plug_id=>wwv_flow_imp.id(203476334075951888)
,p_template=>4072358936313175081
,p_display_sequence=>10
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_new_grid_row=>false
,p_grid_column_span=>6
,p_display_point=>'SUB_REGIONS'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    z.zawodnik_id,',
'    z.numer_koszulki as NR,',
'    z.imie || '' '' || z.nazwisko as ZAWODNIK,',
'    z.pozycja,',
'    ',
'   ',
'    CASE ',
unistr('        WHEN sm.czy_w_podstawowym_skladzie = ''T'' THEN ''Wyj\015Bciowa 11'' '),
unistr('        ELSE ''\0141awka'' '),
'    END as STATUS,',
'    ',
'   ',
'    sm.rozegrane_minuty || '' min'' as MINUTY,',
'    ',
'   ',
'    sm.ocena as OCENA,',
'    ',
'    ',
'    CASE ',
'        WHEN sm.liczba_bramek > 0 THEN ',
unistr('            ''<span style="font-weight:bold; color:green;">\26BD '' || sm.liczba_bramek || ''</span>'''),
'        ELSE NULL ',
'    END as GOLE,',
'    ',
'',
'    CASE ',
'        WHEN sm.liczba_asyst > 0 THEN',
unistr('            ''<span style="font-weight:bold; color:green;">\D83D\DC5F '' || sm.liczba_asyst || ''</span>'''),
'        ELSE NULL',
'    END as ASYSTY, ',
'    ',
'    ',
'    CASE ',
'        WHEN sm.czerwone_kartki > 0 THEN ',
'            ''<span class="fa fa-square" style="color: #DC143C; font-size: 1.2em;" title="Czerwona kartka"></span>''',
'        WHEN sm.zolte_kartki > 0 THEN ',
unistr('            ''<span class="fa fa-square" style="color: #FFD700; font-size: 1.2em;" title="\017B\00F3\0142ta kartka"></span>'''),
'        ELSE NULL ',
'    END as KARTKI',
'    ',
'FROM statystyka_meczowa sm',
'JOIN zawodnik z ON sm.zawodnik_id = z.zawodnik_id',
'WHERE sm.mecz_id = :P9_MECZ_ID',
'  AND z.druzyna_id = 1',
'ORDER BY sm.czy_w_podstawowym_skladzie DESC, sm.rozegrane_minuty DESC'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2538654340625403440
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_no_data_found=>unistr('Protok\00F3\0142 meczowy nie zosta\0142 jeszcze uzupe\0142niony. Kliknij Edytuj, aby doda\0107 statystyki')
,p_query_num_rows_type=>'NEXT_PREVIOUS_LINKS'
,p_pagination_display_position=>'BOTTOM_RIGHT'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
