wwv_flow_imp_page.create_report_region(
 p_id=>wwv_flow_imp.id(203476406172951889)
,p_name=>'H2H z rywalem'
,p_title=>'H2H z rywalem'
,p_parent_plug_id=>wwv_flow_imp.id(203476334075951888)
,p_template=>4072358936313175081
,p_display_sequence=>30
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_new_grid_row=>false
,p_display_point=>'SUB_REGIONS'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    m.data,',
'   ',
'    CASE ',
'        WHEN (m.druzyna_gospodarz_id = 1 AND m.wynik_gospodarza > m.wynik_goscia) OR ',
'             (m.druzyna_gosc_id = 1 AND m.wynik_goscia > m.wynik_gospodarza) THEN ''u-success-text''',
'        WHEN m.wynik_gospodarza = m.wynik_goscia THEN ''u-warning-text'' ',
'        ELSE ''u-danger-text''',
'    END as klasa_koloru,',
'    ',
'    dg.nazwa_druzyny || '' vs '' || dgo.nazwa_druzyny as Mecz,',
'    m.wynik_gospodarza || '':'' || m.wynik_goscia as Wynik',
'FROM mecz m',
'JOIN druzyna dg ON m.druzyna_gospodarz_id = dg.druzyna_id',
'JOIN druzyna dgo ON m.druzyna_gosc_id = dgo.druzyna_id',
'WHERE (',
'    ',
'    (m.druzyna_gospodarz_id = 1 AND m.druzyna_gosc_id = (SELECT CASE WHEN druzyna_gospodarz_id = 1 THEN druzyna_gosc_id ELSE druzyna_gospodarz_id END FROM mecz WHERE mecz_id = :P9_MECZ_ID))',
'    OR',
'    (m.druzyna_gosc_id = 1 AND m.druzyna_gospodarz_id = (SELECT CASE WHEN druzyna_gospodarz_id = 1 THEN druzyna_gosc_id ELSE druzyna_gospodarz_id END FROM mecz WHERE mecz_id = :P9_MECZ_ID))',
')',
'AND m.mecz_id != :P9_MECZ_ID',
'ORDER BY m.data DESC',
'FETCH FIRST 5 ROWS ONLY'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>false
,p_query_row_template=>2538654340625403440
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_num_rows_type=>'NEXT_PREVIOUS_LINKS'
,p_pagination_display_position=>'BOTTOM_RIGHT'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
