wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(203478473013951910)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Dodanie zawodnikow domyslnych'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('-- Wstaw wszystkich aktywnych zawodnik\00F3w z Twojej dru\017Cyny (ID 1)'),
'INSERT INTO statystyka_meczowa (',
'    mecz_id, zawodnik_id, rozegrane_minuty, liczba_bramek, ',
'    liczba_asyst, zolte_kartki, czerwone_kartki, czy_w_podstawowym_skladzie',
')',
'SELECT ',
'    :P10_MECZ_ID, ',
'    zawodnik_id, ',
unistr('    0, 0, 0, 0, 0, ''N'' -- Domy\015Blne warto\015Bci'),
'FROM zawodnik',
'WHERE druzyna_id = 1 ',
unistr('  AND status_zawodnika = ''Aktywny'' -- Je\015Bli masz tak\0105 kolumn\0119'),
unistr('  AND czy_kontuzjowny = ''N'' -- Opcjonalnie: pomi\0144 kontuzjowanych'),
'  AND NOT EXISTS (',
'      SELECT 1 FROM statystyka_meczowa ',
'      WHERE mecz_id = :P10_MECZ_ID AND zawodnik_id = zawodnik.zawodnik_id',
'  );'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(203478415201951909)
,p_internal_uid=>100245113817444643
);
end;
