,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
unistr('/* Wy\015Brodkowanie kart wewn\0105trz kontenera */'),
'#kpi-cards .a-CardView-items {',
'    justify-content: center;',
'}',
'',
'#transfer-cards .a-CardView-items { justify-content: center; }'))
,p_page_template_options=>'#DEFAULT#'
,p_protection_level=>'C'
,p_page_component_map=>'23'
);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(204514813502215272)
,p_plug_name=>unistr('Lista Transfer\00F3w')
,p_title=>unistr('Lista Transfer\00F3w')
,p_region_name=>'transfer-cards'
,p_region_template_options=>'#DEFAULT#:t-CardsRegion--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2072724515482255512
,p_plug_display_sequence=>30
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    t.transfer_id,',
'    t.data_transferu,',
'    TO_CHAR(t.data_transferu, ''DD.MM.YYYY'') as DATA_FMT,',
'',
'    -- Dane Zawodnika',
'    z.imie || '' '' || z.nazwisko as PILKARZ,',
'    z.pozycja,',
'',
'    -- Logika Transferu (IN/OUT)',
'    CASE ',
'        WHEN t.klub_docelowy_id = 1 THEN ''IN'' ',
'        ELSE ''OUT'' ',
'    END as KIERUNEK,',
'',
unistr('    -- Klub Rywala (Je\015Bli przychodzi, to sk\0105d. Je\015Bli odchodzi, to dok\0105d)'),
'    CASE ',
'        WHEN t.klub_docelowy_id = 1 THEN d_zrodlo.nazwa_druzyny',
'        ELSE d_cel.nazwa_druzyny',
'    END as KLUB_RYWALA,',
'',
'    -- Logo Rywala',
'    NVL(CASE ',
'        WHEN t.klub_docelowy_id = 1 THEN d_zrodlo.herb_url',
'        ELSE d_cel.herb_url',
'    END, ''https://cdn-icons-png.flaticon.com/512/18/18404.png'') as LOGO_RYWALA,',
'',
'    -- Kwota sformatowana',
unistr('    TO_CHAR(t.kwota_transferu, ''999G999G999'') || '' \20AC'' as KWOTA,'),
'    t.typ_transferu,',
'',
'    -- Kolory',
'    CASE ',
unistr('        WHEN t.klub_docelowy_id = 1 THEN ''#28a745'' -- Zielony (Przyszed\0142)'),
unistr('        ELSE ''#dc3545'' -- Czerwony (Odszed\0142)'),
'    END as KOLOR_PASKA',
'',
'FROM transfer t',
'JOIN zawodnik z ON t.zawodnik_id = z.zawodnik_id',
'JOIN druzyna d_zrodlo ON t.klub_zrodlowy_id = d_zrodlo.druzyna_id',
'JOIN druzyna d_cel ON t.klub_docelowy_id = d_cel.druzyna_id',
'WHERE t.klub_zrodlowy_id = 1 OR t.klub_docelowy_id = 1',
'ORDER BY t.data_transferu DESC'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_CARDS'
,p_plug_query_num_rows=>10
,p_plug_query_num_rows_type=>'SET'
,p_show_total_row_count=>true
);
wwv_flow_imp_page.create_card(
 p_id=>wwv_flow_imp.id(204516558240215289)
