wwv_flow_imp_page.create_jet_chart_series(
 p_id=>wwv_flow_imp.id(204516184376215286)
,p_chart_id=>wwv_flow_imp.id(204516155984215285)
,p_seq=>10
,p_name=>'Finanse'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- Seria 1: WYDATKI (Klub docelowy to my = 1)',
'SELECT ',
'    EXTRACT(YEAR FROM data_transferu) as ROK,',
'    ''Wydatki'' as SERIA,',
'    SUM(kwota_transferu) as KWOTA,',
unistr('    1 as SORT_ORDER -- \017Beby wydatki by\0142y np. pierwsze'),
'FROM transfer',
'WHERE klub_docelowy_id = 1',
'GROUP BY EXTRACT(YEAR FROM data_transferu)',
'',
'UNION ALL',
'',
unistr('-- Seria 2: PRZYCHODY (Klub \017Ar\00F3d\0142owy to my = 1)'),
'SELECT ',
'    EXTRACT(YEAR FROM data_transferu) as ROK,',
'    ''Przychody'' as SERIA,',
'    SUM(kwota_transferu) as KWOTA,',
'    2 as SORT_ORDER',
'FROM transfer',
'WHERE klub_zrodlowy_id = 1',
'GROUP BY EXTRACT(YEAR FROM data_transferu)',
'',
'ORDER BY ROK DESC, SORT_ORDER'))
,p_series_name_column_name=>'SERIA'
,p_items_value_column_name=>'KWOTA'
,p_items_label_column_name=>'ROK'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
,p_items_label_display_as=>'PERCENT'
,p_threshold_display=>'onIndicator'
);
