wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(204516640658215290)
,p_plug_name=>'Podsumowanie Finansowe'
,p_title=>'Podsumowanie Finansowe'
,p_plug_display_sequence=>10
,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_wydatki_num   NUMBER;',
'  v_przychody_num NUMBER;',
'  v_bilans_num    NUMBER;',
'  ',
'  v_wydatki_str   VARCHAR2(100);',
'  v_przychody_str VARCHAR2(100);',
'  v_bilans_str    VARCHAR2(100);',
'BEGIN',
'  -- 1. OBLICZENIA (Dla Twojego klubu ID=1)',
'  SELECT ',
'    NVL(SUM(CASE WHEN klub_docelowy_id = 1 THEN kwota_transferu ELSE 0 END), 0),',
'    NVL(SUM(CASE WHEN klub_zrodlowy_id = 1 THEN kwota_transferu ELSE 0 END), 0)',
'  INTO v_wydatki_num, v_przychody_num',
'  FROM transfer;',
'',
'  v_bilans_num := v_przychody_num - v_wydatki_num;',
'',
'  -- 2. FORMATOWANIE WALUTY',
unistr('  v_wydatki_str   := TRIM(TO_CHAR(v_wydatki_num, ''999G999G999G999'')) || '' \20AC'';'),
unistr('  v_przychody_str := TRIM(TO_CHAR(v_przychody_num, ''999G999G999G999'')) || '' \20AC'';'),
unistr('  v_bilans_str    := TRIM(TO_CHAR(ABS(v_bilans_num), ''999G999G999G999'')) || '' \20AC'';'),
'  ',
unistr('  -- Dodanie minusa je\015Bli strata'),
'  IF v_bilans_num < 0 THEN v_bilans_str := ''- '' || v_bilans_str; END IF;',
'',
'',
unistr('  -- 3. GENEROWANIE HTML (Flexbox Centruj\0105cy)'),
'  htp.p(''<div style="width: 100%; display: flex; justify-content: center; gap: 20px; flex-wrap: wrap; margin-bottom: 20px;">'');',
'',
'      -- KAFELEK 1: WYDATKI',
'      htp.p(''<div style="background: #fff; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); padding: 20px; width: 300px; text-align: left; border-top: 4px solid #dc3545;">'');',
'        htp.p(''<div style="display:flex; align-items:center; margin-bottom: 10px;">'');',
'           htp.p(''<span class="fa fa-arrow-down-alt u-danger-text" style="font-size: 1.2rem; margin-right: 10px;"></span>'');',
'           htp.p(''<span style="font-weight: bold; color: #555;">Wydatki</span>'');',
'        htp.p(''</div>'');',
'        htp.p(''<div style="font-size: 1.8rem; font-weight: 800; color: #dc3545;">'' || v_wydatki_str || ''</div>'');',
unistr('        htp.p(''<div style="font-size: 0.8rem; color: #999;">Wyp\0142yw got\00F3wki</div>'');'),
'      htp.p(''</div>'');',
'',
'      -- KAFELEK 2: PRZYCHODY',
'      htp.p(''<div style="background: #fff; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); padding: 20px; width: 300px; text-align: left; border-top: 4px solid #28a745;">'');',
'        htp.p(''<div style="display:flex; align-items:center; margin-bottom: 10px;">'');',
'           htp.p(''<span class="fa fa-arrow-up-alt u-success-text" style="font-size: 1.2rem; margin-right: 10px;"></span>'');',
'           htp.p(''<span style="font-weight: bold; color: #555;">Przychody</span>'');',
'        htp.p(''</div>'');',
'        htp.p(''<div style="font-size: 1.8rem; font-weight: 800; color: #28a745;">'' || v_przychody_str || ''</div>'');',
unistr('        htp.p(''<div style="font-size: 0.8rem; color: #999;">Wp\0142yw got\00F3wki</div>'');'),
'      htp.p(''</div>'');',
'',
'      -- KAFELEK 3: BILANS',
'      htp.p(''<div style="background: #fff; border-radius: 8px; box-shadow: 0 4px 6px rgba(0,0,0,0.05); padding: 20px; width: 300px; text-align: left; border-top: 4px solid #056ace;">'');',
'        htp.p(''<div style="display:flex; align-items:center; margin-bottom: 10px;">'');',
'           htp.p(''<span class="fa fa-balance-scale u-info-text" style="font-size: 1.2rem; margin-right: 10px;"></span>'');',
'           htp.p(''<span style="font-weight: bold; color: #555;">Bilans</span>'');',
'        htp.p(''</div>'');',
'        htp.p(''<div style="font-size: 1.8rem; font-weight: 800; color: #056ace;">'' || v_bilans_str || ''</div>'');',
'        htp.p(''<div style="font-size: 0.8rem; color: #999;">Zysk / Strata</div>'');',
'      htp.p(''</div>'');',
'',
'  htp.p(''</div>''); -- Koniec kontenera',
'END;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
);
