);
wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(205741351931846431)
,p_plug_name=>'Statystyki Sezonu'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>10
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    z.imie || '' '' || z.nazwisko as PILKARZ,',
'    z.pozycja,',
'    z.numer_koszulki,',
'    d.nazwa_druzyny as KLUB,',
'    s.sezon,',
'    s.liczba_meczy,',
'    s.liczba_bramek,',
'    s.liczba_asyst,',
'    (s.liczba_bramek + s.liczba_asyst) as KANADYJSKA,',
'    s.zolte_kartki,',
'    s.czerwone_kartki,',
'    s.minuty_rozegrane,',
'    s.liczba_czystych_kont,',
unistr('    -- Wywo\0142anie funkcji oceny (opcjonalnie, bo mo\017Ce zwalnia\0107 raport)'),
'    OBLICZ_SREDNIA_OCENE_ZAWODNIKA(z.zawodnik_id, s.sezon) as SREDNIA_OCENA',
'FROM STATYSTYKA s',
'JOIN ZAWODNIK z ON s.zawodnik_id = z.zawodnik_id',
'JOIN DRUZYNA d ON z.druzyna_id = d.druzyna_id',
'ORDER BY s.liczba_bramek DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_prn_page_header=>'Statystyki Sezonu'
);
